SELECT
    VISIT_ID, CUSTOMER_ID, DESIGNER_ID, SURVEY_TOKEN, TOKEN_EXPIRES_DT,
    STATUS, VISIT_DT, SUBMIT_DT, REG_DT, MOD_DT
FROM tb_visit_record
WHERE VISIT_ID = #{visitId}
AND DESIGNER_ID = #{designerId}


SELECT
    VISIT_ID, STATUS, VISIT_DT, SERVICES,
    TREATMENT_PRODUCT, TREATMENT_DETAIL, TREATMENT_NOTE
FROM tb_visit_record
WHERE CUSTOMER_ID = #{customerId}
AND   DESIGNER_ID = #{designerId}

    AND VISIT_DT >= #{startDate}


    AND VISIT_DT < DATE_ADD(#{endDate}, INTERVAL 1 DAY)


    AND SERVICES IN

        #{code}


ORDER BY VISIT_DT DESC
